const invoices = items.map(item => item.json);

const invoiceCounts = {};
for (const invoice of invoices) {
  invoiceCounts[invoice.invoice_id] = (invoiceCounts[invoice.invoice_id] || 0) + 1;
}

function parseDate(value) {
  if (!value) return null;
  return new Date(value);
}

function round2(value) {
  return Math.round(Number(value) * 100) / 100;
}

function getSuggestedAction(issues) {
  const issueText = issues.join(" ").toLowerCase();

  if (issueText.includes("duplicate")) {
    return "Check source system before posting or payment.";
  }

  if (issueText.includes("vat")) {
    return "Verify VAT calculation and supplier invoice details.";
  }

  if (issueText.includes("payment date")) {
    return "Confirm payment date from bank or payment system.";
  }

  if (issueText.includes("due date")) {
    return "Confirm invoice date and payment terms.";
  }

  if (issueText.includes("account code")) {
    return "Confirm correct account code before posting.";
  }

  if (issueText.includes("supplier vat")) {
    return "Check vendor master data or request missing supplier VAT number.";
  }

  return "Finance team should review missing or inconsistent data.";
}

function getCategory(issues) {
  const issueText = issues.join(" ").toLowerCase();

  if (issueText.includes("duplicate")) return "Duplicate risk";
  if (issueText.includes("vat")) return "VAT / tax validation";
  if (issueText.includes("payment")) return "Reconciliation";
  if (issueText.includes("due date")) return "Date validation";
  if (issueText.includes("account code")) return "Accounting coding";
  if (issueText.includes("supplier")) return "Vendor data quality";

  return "Data quality";
}

function getReviewNote(invoice, issues, priority) {
  if (issues.length === 0) {
    return "No exception detected. This record appears ready for normal finance processing.";
  }

  return `This record needs ${priority.toLowerCase()} priority review because: ${issues.join("; ")}. Suggested next step: ${getSuggestedAction(issues)}`;
}

const validated = invoices.map(invoice => {
  const issues = [];

  const expectedVat = round2(invoice.net_amount * 0.24);
  const expectedTotal = round2(invoice.net_amount + invoice.vat_amount);

  const invoiceDate = parseDate(invoice.invoice_date);
  const dueDate = parseDate(invoice.due_date);

  if (!invoice.invoice_id) {
    issues.push("Missing invoice ID");
  }

  if (!invoice.supplier_vat) {
    issues.push("Missing supplier VAT number");
  }

  if (invoiceCounts[invoice.invoice_id] > 1) {
    issues.push("Possible duplicate invoice ID");
  }

  if (invoiceDate && dueDate && dueDate < invoiceDate) {
    issues.push("Due date is before invoice date");
  }

  if (round2(invoice.vat_amount) !== expectedVat) {
    issues.push(`VAT mismatch: expected ${expectedVat}, found ${invoice.vat_amount}`);
  }

  if (round2(invoice.total_amount) !== expectedTotal) {
    issues.push(`Total mismatch: expected ${expectedTotal}, found ${invoice.total_amount}`);
  }

  if (String(invoice.status).toLowerCase() === "paid" && !invoice.payment_date) {
    issues.push("Invoice marked as paid but payment date is missing");
  }

  if (!invoice.account_code) {
    issues.push("Missing account code");
  }

  let reviewStatus = "OK";
  let priority = "Low";

  if (issues.length === 1) {
    reviewStatus = "Needs Review";
    priority = "Medium";
  }

  if (issues.length >= 2) {
    reviewStatus = "Exception";
    priority = "High";
  }

  const category = getCategory(issues);
  const suggestedAction = getSuggestedAction(issues);
  const reviewNote = getReviewNote(invoice, issues, priority);

  return {
    json: {
      invoice_id: invoice.invoice_id,
      supplier_name: invoice.supplier_name,
      total_amount: invoice.total_amount,
      currency: invoice.currency,
      review_status: reviewStatus,
      priority,
      exception_category: category,
      issues: issues.length ? issues.join("; ") : "No issue",
      suggested_action: suggestedAction,
      review_note: reviewNote
    }
  };
});

return validated;

const records = items.map(item => item.json);

const totalRecords = records.length;
const okRecords = records.filter(r => r.review_status === "OK").length;
const needsReview = records.filter(r => r.review_status === "Needs Review").length;
const exceptions = records.filter(r => r.review_status === "Exception").length;

const highPriority = records.filter(r => r.priority === "High").length;
const mediumPriority = records.filter(r => r.priority === "Medium").length;
const lowPriority = records.filter(r => r.priority === "Low").length;

const exceptionValue = records
  .filter(r => r.review_status !== "OK")
  .reduce((sum, r) => sum + Number(r.total_amount || 0), 0);

const exceptionRows = records
  .filter(r => r.review_status !== "OK")
  .map(r => {
    return {
      invoice_id: r.invoice_id,
      supplier_name: r.supplier_name,
      total_amount: r.total_amount,
      currency: r.currency,
      review_status: r.review_status,
      priority: r.priority,
      exception_category: r.exception_category,
      issues: r.issues,
      suggested_action: r.suggested_action
    };
  });

let summaryText = "";

if (exceptions > 0) {
  summaryText = `${totalRecords} finance records were checked. ${okRecords} records are ready for normal processing, ${needsReview} need review, and ${exceptions} are high-risk exceptions. The total value affected by review items is ${exceptionValue} EUR. Finance should prioritize duplicate, VAT, and reconciliation-related issues before posting, payment, or close.`;
} else if (needsReview > 0) {
  summaryText = `${totalRecords} finance records were checked. ${okRecords} records are ready for normal processing and ${needsReview} need review. No high-risk exceptions were detected.`;
} else {
  summaryText = `${totalRecords} finance records were checked. No exceptions were detected. All records appear ready for normal processing.`;
}

return [
  {
    json: {
      report_title: "AI-Assisted Finance Exception Monitoring Report",
      generated_for: "Finance operations review",
      total_records_checked: totalRecords,
      ok_records: okRecords,
      needs_review_records: needsReview,
      exception_records: exceptions,
      high_priority_items: highPriority,
      medium_priority_items: mediumPriority,
      low_priority_items: lowPriority,
      total_value_requiring_review_eur: exceptionValue,
      executive_summary: summaryText,
      exception_rows: exceptionRows
    }
  }
];

const report = items[0].json;

const rows = report.exception_rows || [];

let exceptionTable = "";

if (rows.length === 0) {
  exceptionTable = "No exceptions detected.";
} else {
  exceptionTable = `
| Invoice ID | Supplier | Amount | Status | Priority | Category | Issue | Suggested Action |
|---|---|---:|---|---|---|---|---|
${rows.map(r => `| ${r.invoice_id} | ${r.supplier_name} | ${r.total_amount} ${r.currency} | ${r.review_status} | ${r.priority} | ${r.exception_category} | ${r.issues} | ${r.suggested_action} |`).join("\n")}
`;
}

const markdownReport = `# ${report.report_title}

## Purpose

This prototype simulates a finance operations workflow where invoice and transaction records are automatically checked for data quality, reconciliation, VAT, duplicate, and accounting coding issues.

The goal is not to replace accountants, but to help finance teams focus on exceptions instead of manually checking every record.

## Executive Summary

${report.executive_summary}

## Key Metrics

| Metric | Value |
|---|---:|
| Total records checked | ${report.total_records_checked} |
| OK records | ${report.ok_records} |
| Needs review | ${report.needs_review_records} |
| High-risk exceptions | ${report.exception_records} |
| High priority items | ${report.high_priority_items} |
| Medium priority items | ${report.medium_priority_items} |
| Low priority items | ${report.low_priority_items} |
| Total value requiring review | ${report.total_value_requiring_review_eur} EUR |

## Exception Details

${exceptionTable}

## Human-in-the-Loop Control

The workflow does not approve invoices or payments. It only detects issues, classifies review priority, and prepares finance-friendly notes so a human specialist can decide the correct next action.

## Possible Extensions

- Connect to ERP export data
- Add Power Automate or Make integration
- Add real AI explanation using Claude, ChatGPT, or Copilot
- Send exception summary by email or Teams
- Store exception history for audit and follow-up
`;

return [
  {
    json: {
      markdown_report: markdownReport
    }
  }
];
